import React from "react";
import { useState } from "react";
import "./nav.css";

export default function Nav() {
  const [Active, IsActive] = useState("off");

  const handleClick = () => {
    if (Active === "off") {
      IsActive("true");
    } else {
      IsActive("off");
    }
  };
  function handleTextareaChange() {
    console.log("kokot");
  }

  return (
    <div>
      <div
        value={Active.value}
        onChange={handleTextareaChange}
        className="pushMenu"
      ></div>
      <div onClick={handleClick} className="gg-menu-grid-o"></div>
    </div>
  );
}

